var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……흔적이 남아 있어. 벌써 여길 지나쳤나.","JPN":"……痕跡が残っている。もうここを通過したか。","ENG":"...There's a trace. She must have already passed by.","TWN":"……痕跡還在，是有經過這裡嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"빠르군. 전술적인 기조는 용병단 시절과 그대로인가.","JPN":"早いな、戦術的な基調は傭兵時代のままか。","ENG":"Quite fast. Her tactical brain remains the same from her mercenary days.","TWN":"很快啊。戰術風格和在傭兵隊時一樣嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경과 머리를 맞댔다면, 더 좋은 결과를 도출할 수 있었을 텐데.","JPN":"アレンと頭脳を合わせていれば、もっと良い結論が出せていただろうな。","ENG":"Perhaps a better result would've come out if it was discussed with Sir Allen.","TWN":"要是和艾倫卿商量一下，應該能得出更好的結果。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아쉽군. 그렇지 않나?","JPN":"惜しいな。そうは思わんか？","ENG":"What a shame. Don't you agree?","TWN":"可惜了，不是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이런, 정말이지 기습이 안 통하는 상대란 골치 아프네요.","JPN":"やれやれ、まったく不意打ちが通用しない相手って面倒くさいものですね。","ENG":"I must say, enemies who are prepared for ambushes make things so much harder.","TWN":"哎呀，說真的，對手不吃偷襲這招還真的很讓人頭疼呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"목을 노렸는데 생채기도 못 내게 하다니, 매사에 너무 엄격하신 것 아닌가요?","JPN":"首を狙ったのに傷一つ付けさせないなんて、とことん厳しい方ですね？","ENG":"I aimed for your neck, but you wouldn't allow even the slightest slit. Don't you think you're too uptight?","TWN":"好歹也讓我象徵性地弄出些傷口吧，殿下您是不是對每件事都太過嚴格了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"중요한 단서를 이렇게 노골적으로 펼쳐 두는 건 정치에서도 하책이다.","JPN":"重要なヒントをこんなふうにあからさまに広げておくのは、政治においても下策だ。","ENG":"Being unable to conceal your intentions is a critical fault, even in politics.","TWN":"如此露骨地表露自己的目的，在政治上也是下策。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"소년, 공부가 더 필요하겠군.","JPN":"少年、さらなる勉強が必要だな。","ENG":"It is clear that you need to learn more, boy.","TWN":"年輕人，你還需要繼續學習。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어이쿠, 제 인생 설계는 열세 살 때 이미 끝났습니다.","JPN":"おやおや、僕の人生設計は13歳の時に終わっています。","ENG":"Sorry, but my life plans were laid out the minute I turned thirteen.","TWN":"哎呀，我的人生規劃早在我十三歲時就已經做好了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"서른 살 되기 전에 현업에서 은퇴하고 분재나 가꾸면서 유유자적하게 지내는 거죠.","JPN":"30歳になる前に現職を引退して、盆栽でも育てつつ、のんびり生きていくんです。","ENG":"I plan on retiring before thirty, then live a life of peace and tranquility.","TWN":"在三十歲之前退休，養養花，悠閒自在地生活。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오, 그거 참 소박한 꿈이로다.","JPN":"ほお、それはなんとも素朴な夢だ。","ENG":"A humble dream indeed.","TWN":"噢，這個夢想還真樸實無華啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"헌데 그렇다면 홀로 나를 알현하는 짓은 그만두는 편이 낫지 않았나?","JPN":"しかし、それなら単独で私と対峙するのは止めた方が良いのではないか？","ENG":"However, don't you think it was a foolish idea to face me by yourself?","TWN":"不過那樣的話，你是不是最好不要一個人來見我呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그게 말이죠. 문득 재미있는 생각이 떠오르더라고요.","JPN":"はは、それがですね。ふと面白いことを思いついたといいますか。","ENG":"Ha ha. Well, an interesting idea came to mind.","TWN":"哈哈，那個，我突然有一個有趣的想法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이전에 겪었던 상황과 묘하게 비슷한 인상이 든다고나 할까요.","JPN":"前に経験した状況と妙に似ているような感じがするといいますか。","ENG":"Let's say it's strangely similar to something I went through before.","TWN":"可以說和以前經歷的情況有著微妙的相似印象呢。"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 때도 결국에는 미나 양을 보내고 이렇게 남아 있었죠.","JPN":"あの時も結局はミナさんを行かせて、僕一人がこうして残っていました。","ENG":"I had also sent Mina away and dealt with things alone back then.","TWN":"那時候也是我送走了米娜，自己留下來斷後。"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금 와서 생각해 보면, 누가 미리 훈련이라도 시킨 것 아닌가 싶더라고요.","JPN":"今思えば、あらかじめ誰かに訓練されていたんじゃないかという気がするんです。","ENG":"Looking back, it's almost as if someone trained me beforehand.","TWN":"現在想來，是不是有人預知一切，所以提前訓練我。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"기시감이라는 건가. 재미있는 이야기로군.","JPN":"既視感があるということか。面白い話だ。","ENG":"Deja vu, I see. Interesting.","TWN":"似曾相識嗎？很有趣的想法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_45"},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 소년, 그 발상에는 한 가지 큰 문제가 있구나.","JPN":"しかしだ少年、その発想には一つ大きな問題があるようだな。","ENG":"But your assumption has one error, boy.","TWN":"不過年輕人，你這個想法有一個大問題。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_46"},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"용혈도 버린 네가, 나를 얼마나 오래 붙잡아 둘 수 있을 것 같나?","JPN":"龍血も捨てた貴様が、どこまで私を足止めできるというのだ？","ENG":"You have abandoned Dragon Blood, how long do you think you will be able to keep me here?","TWN":"你覺得放棄了龍血的你，能留住我多久呢？"},"stage":{"bg":"MS_1110","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_47"},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"늑대에게도 말했듯이, 불손한 발언에도 정도가 있는 법이다.","JPN":"狼にも言ったが、不遜な発言にも程があるというものだ。","ENG":"As I have said to the Wolf, there's only so much disrespect I can tolerate.","TWN":"就像我對狼也說過的那樣，出言不遜也要有個限度。"},"stage":{"bg":"MS_1110","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_48"},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"죄송하지만 제 혈액형은 AB형입니다.","JPN":"申し訳ありませんが、僕の血液型はAB型です。","ENG":"My blood type is AB, for your information.","TWN":"不好意思，不過我的血型是AB型。"},"stage":{"bg":"MS_1110","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠……?","JPN":"ふむ……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"MS_1110","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_49"},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"용혈이니 뭐니 굉장히 집착하시는데, 핏줄 따라 사는 삶은 이제 관심 없어서요.","JPN":"龍血がなんだのとすごく執着されてますが、僕は血筋にとらわれる人生にはもう興味がないんです。","ENG":"You’re obsessed with Dragon Blood or whatever, but I have no intentions of following whatever bloodline I bear.","TWN":"你好像還對龍血有著非同一般的執著，不過我早就對遵從血脈生活的人生不感興趣了。"},"stage":{"bg":"MS_1111","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"요즘 젊은이들에게 그런 구시대적인 관점을 강요하면 꼰대 소리만 듣는답니다.","JPN":"最近の若者にそんな古い時代の観点を強要すると老害って言われるんですよ。","ENG":"All you’re getting out of me by forcing that old fashioned ideology is being called \\"boomer\\".","TWN":"強迫最近的年輕人接受這種老舊的觀點，只會被人說成是老古板。"},"stage":{"bg":"MS_1111","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"체통을 지키셔야죠, 전하.","JPN":"体裁は気にされた方がいいんじゃないですか、殿下。","ENG":"I’m sure you’re way mightier than that, Your Highness.","TWN":"這樣有失顏面呢，殿下。"},"stage":{"bg":"MS_1111","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……전통을 중시할 줄 모르는군.","JPN":"……伝統に重きを置くことを知らぬようだな。","ENG":"...You lack respect for tradition.","TWN":"……看來你不太尊重傳統啊。"},"stage":{"bg":"MS_1111","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_50"},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"좋다. 어디 시험해 보겠나, 소년.","JPN":"いいだろう。ならば試してみるか、少年。","ENG":"Very well. Try me, boy.","TWN":"很好，那就試試看吧，年輕人。"},"stage":{"bg":"MS_1112","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_51"},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"지배하느냐, 받아들이느냐…….","JPN":"支配するか、受け入れるか……","ENG":"To conquer, or to accept fate...","TWN":"支配，還是被迫接受……"},"stage":{"bg":"MS_1112","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_52"},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어리석은 선조의 과오를 어떻게 해소해야 할지, 여기서 확인하기로 하지.","JPN":"愚かな先祖の過ちをどのように消し去ればいいか、ここで確かめるとしよう。","ENG":"I shall see how you resolve the wrongdoings of your ancestors.","TWN":"你要如何消除先祖們愚蠢的錯誤，就讓我在這裡確認一下吧。"},"stage":{"bg":"MS_1112","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_53"},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그런 거라면 저도 분발해야겠는데요, 황태자 전하.","JPN":"そういうことなら、僕も張り切らないとですね、皇太子殿下。","ENG":"Well then, I guess I will have to try harder, Your Highness.","TWN":"那樣的話，我也要努力了啊，皇太子殿下。"},"stage":{"bg":"MS_1112","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 검이 완성될 때까지 얼마나 많은 피가 흘렀을지, 확인할 가치도 없을 테니까요.","JPN":"その剣が完成するまでどれほどの血が流れたか、確かめる価値もありませんからね。","ENG":"Because I won't need to see how much blood was shed to complete that sword.","TWN":"不用確認也能看得出來，那把劍在完成之前，究竟澆築了多少龍血。"},"stage":{"bg":"MS_1112","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};